import Combine

let publisher = Just("Hello")

let cancellable = publisher
    .sink { value in
        print(value)
    }

Just(42)
    .map { $0 * 2 }
    .sink { print($0) }

let numbers = [1, 2, 3].publisher

numbers
    .map { $0 * 2 }
    .sink { print($0) }

["hello", "world"].publisher
    .map { $0.uppercased() }
    .map { ">> \($0)" }
    .sink { print($0) }

var name: String? = "Thiago"

if let unwrapped = name {
    print(unwrapped)
}

func greet(name: String?) {
    guard let name else { return }
    print("Hello, \(name)")
}

